class Solution:
    def maximumGain(self, s, x, y):
        total = 0
        if x >= y:
            first_pat, first_score, second_pat, second_score = 'ab', x, 'ba', y
        else:
            first_pat, first_score, second_pat, second_score = 'ba', y, 'ab', x
        chars = list(s)
        for pat, score in ((first_pat, first_score), (second_pat, second_score)):
            changed = True
            while changed:
                changed = False
                out = []
                j = 0
                n = len(chars)
                while j < n:
                    if j + 1 < n and chars[j] == pat[0] and chars[j + 1] == pat[1]:
                        total += score
                        j += 2
                        changed = True
                    else:
                        out.append(chars[j])
                        j += 1
                chars = out
        return total

