class Solution:
    def maximumGain(self, s, x, y):
        def remove_pair(string, a, b, score):
            stack = []
            total = 0
            for ch in string:
                if stack and stack[-1] == a and ch == b:
                    stack.pop()
                    total += score
                else:
                    stack.append(ch)
            return ''.join(stack), total

        if x >= y:
            s1, sc1 = remove_pair(s, 'a', 'b', x)
            s2, sc2 = remove_pair(s1, 'b', 'a', y)
        else:
            s1, sc1 = remove_pair(s, 'b', 'a', y)
            s2, sc2 = remove_pair(s1, 'a', 'b', x)
        return sc1 + sc2

