var maximumGain = function(s, x, y) {
    function removePair(str, a, b, score) {
        const stack = [];
        let total = 0;
        for (const ch of str) {
            if (stack.length && stack[stack.length - 1] === a && ch === b) {
                stack.pop();
                total += score;
            } else {
                stack.push(ch);
            }
        }
        return [stack.join(''), total];
    }

    let s1, sc1, s2, sc2;
    if (x >= y) {
        [s1, sc1] = removePair(s, 'a', 'b', x);
        [s2, sc2] = removePair(s1, 'b', 'a', y);
    } else {
        [s1, sc1] = removePair(s, 'b', 'a', y);
        [s2, sc2] = removePair(s1, 'a', 'b', x);
    }
    return sc1 + sc2;
};
